from collections.abc import AsyncIterator, Mapping
from dataclasses import dataclass
from typing import Literal, Protocol, TypedDict, cast

from ollama import AsyncClient

ChatRole = Literal["system", "user", "assistant"]


class ChatMessage(TypedDict):
    role: ChatRole
    content: str


class AsyncOllamaClient(Protocol):
    def chat(
        self,
        *,
        model: str,
        messages: list[ChatMessage],
        stream: Literal[True],
    ) -> AsyncIterator[object]: ...


@dataclass(frozen=True)
class OllamaConfig:
    host: str
    model: str


class OllamaStreamer:
    def __init__(self, config: OllamaConfig, client: AsyncOllamaClient | None = None) -> None:
        self.config = config
        self.client = client or cast(AsyncOllamaClient, AsyncClient(host=config.host))

    async def stream_reply(self, messages: list[ChatMessage]) -> AsyncIterator[str]:
        stream = self.client.chat(model=self.config.model, messages=messages, stream=True)
        async for chunk in stream:
            token = token_from_chunk(chunk)
            if token:
                yield token


def token_from_chunk(chunk: object) -> str:
    if isinstance(chunk, Mapping):
        message = chunk.get("message")
        if isinstance(message, Mapping):
            content = message.get("content")
            return content if isinstance(content, str) else ""
        return ""

    message = getattr(chunk, "message", None)
    content = getattr(message, "content", "")
    return content if isinstance(content, str) else ""

