import httpx
import pytest
from django.test import Client, override_settings

from chat.health import models_from_tags, ollama_health


def test_models_from_tags_uses_name_or_model() -> None:
    payload = {"models": [{"name": "qwen2.5:7b"}, {"model": "other:latest"}]}

    assert models_from_tags(payload) == {"qwen2.5:7b", "other:latest"}


@override_settings(OLLAMA_HOST="http://ollama.test", OLLAMA_MODEL="qwen2.5:7b")
def test_ollama_health_reports_configured_model(monkeypatch: pytest.MonkeyPatch) -> None:
    def fake_get(url: str, timeout: float) -> httpx.Response:
        request = httpx.Request("GET", url)
        payload = {"models": [{"name": "qwen2.5:7b"}]}
        return httpx.Response(200, json=payload, request=request)

    monkeypatch.setattr(httpx, "get", fake_get)

    assert ollama_health() == {"ok": True, "ollama": "reachable", "model": "qwen2.5:7b"}


@override_settings(OLLAMA_HOST="http://ollama.test", OLLAMA_MODEL="missing")
def test_health_check_fails_when_model_missing(
    monkeypatch: pytest.MonkeyPatch,
    client: Client,
) -> None:
    def fake_get(url: str, timeout: float) -> httpx.Response:
        request = httpx.Request("GET", url)
        return httpx.Response(200, json={"models": []}, request=request)

    monkeypatch.setattr(httpx, "get", fake_get)

    response = client.get("/healthz/")

    assert response.status_code == 503
    assert response.json() == {"ok": False, "ollama": "reachable", "model": "missing"}

(() => {
  const form = document.querySelector("#chat-form");
  const input = document.querySelector("#message-input");
  const log = document.querySelector("#chat-log");
  const state = document.querySelector("#connection-state");
  const error = document.querySelector("#chat-error");
  const sendButton = document.querySelector("#send-button");
  let socket = null;
  let currentAssistant = null;

  const wsUrl = () => {
    const protocol = window.location.protocol === "https:" ? "wss" : "ws";
    return `${protocol}://${window.location.host}/ws/chat/`;
  };

  const setState = (label) => {
    state.textContent = label;
  };

  const setBusy = (busy) => {
    input.disabled = busy;
    sendButton.disabled = busy;
  };

  const hideError = () => {
    error.classList.add("hidden");
    error.textContent = "";
  };

  const showError = (message) => {
    error.textContent = message;
    error.classList.remove("hidden");
  };

  const removeEmptyState = () => {
    document.querySelector("#empty-state")?.remove();
  };

  const appendBubble = (role, text = "") => {
    removeEmptyState();
    const bubble = document.createElement("article");
    bubble.className = `chat-bubble chat-bubble-${role}`;
    bubble.textContent = text;
    log.appendChild(bubble);
    log.scrollTop = log.scrollHeight;
    return bubble;
  };

  const connect = () => {
    socket = new WebSocket(wsUrl());
    socket.addEventListener("open", () => setState("online"));
    socket.addEventListener("close", () => {
      setState("offline");
      setBusy(false);
      window.setTimeout(connect, 1500);
    });
    socket.addEventListener("error", () => showError("WebSocket connection failed."));
    socket.addEventListener("message", (event) => {
      const payload = JSON.parse(event.data);
      if (payload.type === "start") {
        currentAssistant = appendBubble("assistant", "");
      }
      if (payload.type === "token" && currentAssistant) {
        currentAssistant.textContent += payload.content;
        log.scrollTop = log.scrollHeight;
      }
      if (payload.type === "end") {
        currentAssistant = null;
        setBusy(false);
        input.focus();
      }
      if (payload.type === "error") {
        showError(payload.content);
        currentAssistant = null;
        setBusy(false);
      }
    });
  };

  form.addEventListener("submit", (event) => {
    event.preventDefault();
    hideError();
    const message = input.value.trim();
    if (!message || !socket || socket.readyState !== WebSocket.OPEN) {
      showError("Connection is not ready.");
      return;
    }
    appendBubble("user", message);
    input.value = "";
    setBusy(true);
    socket.send(JSON.stringify({ message }));
  });

  connect();
})();

from typing import NotRequired, TypedDict

import httpx
from django.conf import settings
from django.http import HttpRequest, JsonResponse


class HealthPayload(TypedDict):
    ok: bool
    ollama: str
    model: NotRequired[str]
    error: NotRequired[str]


def health_check(request: HttpRequest) -> JsonResponse:
    """Return app health including Ollama reachability.

    Example: `GET /healthz/` returns HTTP 200 only when Ollama responds and
    the configured model is available.
    """
    result = ollama_health()
    status_code = 200 if result["ok"] else 503
    return JsonResponse(result, status=status_code)


def ollama_health() -> HealthPayload:
    """Check the configured Ollama host and model.

    Example: `ollama_health()["ok"]` is true when `/api/tags` lists the model.
    """
    try:
        response = httpx.get(f"{settings.OLLAMA_HOST}/api/tags", timeout=2.0)
        response.raise_for_status()
    except httpx.HTTPError as exc:
        return {"ok": False, "ollama": "unreachable", "error": str(exc)}

    payload = response.json()
    models = models_from_tags(payload)
    model = str(settings.OLLAMA_MODEL)
    return {"ok": model in models, "ollama": "reachable", "model": model}


def models_from_tags(payload: object) -> set[str]:
    """Extract model names from an Ollama `/api/tags` payload.

    Example: `models_from_tags({"models": [{"name": "qwen2.5:7b"}]})`.
    """
    if not isinstance(payload, dict):
        return set()

    models = payload.get("models")
    if not isinstance(models, list):
        return set()

    return {model_name(model) for model in models if model_name(model)}


def model_name(model: object) -> str:
    """Extract a single Ollama model name.

    Example: `model_name({"name": "qwen2.5:7b"})` returns the model name.
    """
    if not isinstance(model, dict):
        return ""

    name = model.get("name") or model.get("model")
    return name if isinstance(name, str) else ""

#!/usr/bin/env python
"""Django's command-line utility for administrative tasks."""

import os
import sys


def main():
    """Run administrative tasks."""
    os.environ.setdefault("DJANGO_SETTINGS_MODULE", "config.settings")
    try:
        from django.core.management import execute_from_command_line
    except ImportError as exc:
        raise ImportError(
            "Couldn't import Django. Are you sure it's installed and "
            "available on your PYTHONPATH environment variable? Did you "
            "forget to activate a virtual environment?"
        ) from exc
    execute_from_command_line(sys.argv)


if __name__ == "__main__":
    main()
